// ============================================
// 🔄 Pour chaque jeune, construire les requêtes API
// ============================================

const jeunes = $('📋 Lire jeunes éligibles').all();
const token = $('🔐 Token France Travail').first().json.access_token;

const results = [];

for (const item of jeunes) {
  const j = item.json;
  const dept = j.departement || '75';
  const romes = j.codes_rome_suggeres;

  const deptCoords = {
    '06': { lat: 43.7102, lon: 7.2620 },
    '13': { lat: 43.2965, lon: 5.3698 },
    '33': { lat: 44.8378, lon: -0.5792 },
    '34': { lat: 43.6110, lon: 3.8767 },
    '35': { lat: 48.1173, lon: -1.6778 },
    '44': { lat: 47.2184, lon: -1.5536 },
    '59': { lat: 50.6292, lon: 3.0573 },
    '69': { lat: 45.7640, lon: 4.8357 },
    '75': { lat: 48.8566, lon: 2.3522 },
    '77': { lat: 48.5272, lon: 2.6987 },
    '78': { lat: 48.8014, lon: 2.1301 },
    '89': { lat: 47.7973, lon: 3.5674 },
    '91': { lat: 48.6293, lon: 2.4396 },
    '92': { lat: 48.8283, lon: 2.2399 },
    '93': { lat: 48.9100, lon: 2.4200 },
    '94': { lat: 48.7904, lon: 2.4753 },
    '95': { lat: 49.0354, lon: 2.0733 }
  };
  const coords = deptCoords[dept] || deptCoords['75'];

  results.push({
    json: {
      jeune: j,
      token: token,
      ft_url: `https://api.francetravail.io/partenaire/offresdemploi/v2/offres/search?departement=${dept}&distance=20&codeROME=${romes}&range=0-49`,
      lba_url: `https://api.apprentissage.beta.gouv.fr/api/job/v1/search?latitude=${coords.lat}&longitude=${coords.lon}&radius=25&romes=${romes}`,
      coords: coords
    }
  });
}

return results;

// ============================================
// 🎯 MOTEUR DE SCORING
// ============================================

const ftData = $('📡 Appel France Travail').first().json;
const lbaData = $('📡 Appel Bonne Alternance').first().json;
const jeune = $('🔁 Un jeune à la fois').first().json.jeune;

const niveauFr = jeune.niveau_francais_declare || '';
const freinLangue = niveauFr.includes('Débutant') || niveauFr.includes('Non francophone');
const romesJeune = (jeune.codes_rome_suggeres || '').split(',').map(r => r.trim());
const deptJeune = jeune.departement || '';

function scoreOffre(offre, source) {
  let score = 0;
  const detail = {};

  const romeOffre = source === 'FT' ? (offre.romeCode || '') : '';
  if (source === 'FT' && romesJeune.includes(romeOffre)) {
    score += 30; detail.rome = 30;
  } else if (source === 'LBA') {
    score += 25; detail.rome = 25;
  } else { detail.rome = 0; }

  if (source === 'FT') {
    const debutant = offre.experienceExige === 'D' || offre.experienceExige === 'S';
    if (debutant) { score += 25; detail.debutant = 25; }
    else { detail.debutant = 0; }
  } else { score += 25; detail.debutant = 25; }

  if (source === 'FT') {
    const deptOffre = offre.lieuTravail?.codePostal?.substring(0, 2) || '';
    if (deptOffre === deptJeune) { score += 20; detail.geo = 20; }
    else if (['75','92','93','94'].includes(deptOffre) && ['75','92','93','94'].includes(deptJeune)) {
      score += 15; detail.geo = 15;
    } else { detail.geo = 0; }
  } else { score += 15; detail.geo = 15; }

  if (freinLangue) {
    if (source === 'FT') {
      const langues = offre.langues || [];
      if (langues.length === 0) { score += 15; detail.langue = 15; }
      else { detail.langue = 0; }
    } else { score += 10; detail.langue = 10; }
  } else { score += 15; detail.langue = 15; }

  if (source === 'FT') {
    const permis = offre.permis || [];
    if (permis.length === 0) { score += 5; detail.permis = 5; }
    else { detail.permis = 0; }
  } else { score += 5; detail.permis = 5; }

  const dispoAlternance = (jeune.disponibilite || '').toLowerCase().includes('alternance');
  if (source === 'LBA' && dispoAlternance) { score += 5; detail.type_contrat = 5; }
  else if (source === 'FT' && offre.alternance === true && dispoAlternance) { score += 5; detail.type_contrat = 5; }
  else { detail.type_contrat = 0; }

  return { score, detail };
}

const offresFT = (ftData.resultats || []).map(o => {
  const { score, detail } = scoreOffre(o, 'FT');
  return {
    source: 'France Travail', offre_id: o.id,
    titre: o.intitule, entreprise: o.entreprise?.nom || 'Non communiqué',
    lieu: o.lieuTravail?.libelle || '',
    departement_offre: o.lieuTravail?.codePostal?.substring(0, 2) || '',
    type_contrat: o.typeContratLibelle || o.typeContrat || '',
    est_alternance: o.alternance === true, debutant_accepte: o.experienceExige === 'D',
    url_offre: o.origineOffre?.urlOrigine || `https://candidat.francetravail.fr/offres/recherche/detail/${o.id}`,
    score, score_detail: detail
  };
});

const jobs = (lbaData.jobs || []).map(j => {
  const { score, detail } = scoreOffre(j, 'LBA');
  return {
    source: 'La Bonne Alternance', offre_id: j.identifier?.partner_job_id || j.identifier?.id || '',
    titre: j.offer?.title || '', entreprise: j.workplace?.name || 'Non communiqué',
    lieu: j.workplace?.location?.city || '', departement_offre: '',
    type_contrat: (j.contract?.type || []).join(', '),
    est_alternance: true, debutant_accepte: true,
    url_offre: j.apply?.url || '',
    score, score_detail: detail
  };
});

const allOffres = [...offresFT, ...jobs]
  .filter(o => o.score >= 60 && o.offre_id)
  .sort((a, b) => b.score - a.score)
  .slice(0, 5);

const esc = (v) => {
  if (v === null || v === undefined) return 'NULL';
  return "'" + String(v).replace(/'/g, "''").substring(0, 2000) + "'";
};

const results = [];
for (const o of allOffres) {
  const sql = `INSERT INTO koda_matchs (jeune_id, source, offre_id, titre, entreprise, lieu, departement_offre, type_contrat, est_alternance, debutant_accepte, score, score_detail, url_offre, statut) VALUES (${esc(jeune.airtable_id)}, ${esc(o.source)}, ${esc(o.offre_id)}, ${esc(o.titre)}, ${esc(o.entreprise)}, ${esc(o.lieu)}, ${esc(o.departement_offre)}, ${esc(o.type_contrat)}, ${o.est_alternance}, ${o.debutant_accepte}, ${o.score}, '${JSON.stringify(o.score_detail).replace(/'/g, "''")}', ${esc(o.url_offre)}, 'nouvelle') ON CONFLICT (jeune_id, offre_id) DO NOTHING;`;
  results.push({ json: { query: sql, jeune_prenom: jeune.prenom, offre_titre: o.titre, score: o.score } });
}

if (results.length === 0) {
  results.push({ json: { query: null, jeune_prenom: jeune.prenom, offre_titre: 'Aucun match >= 60', score: 0 } });
}

return results;
